metadata = {
    'apiLevel': '2.8',
    'protocolName': 'tamGenetics_normalizationPooling',
    'author': 'Rachel Voyt',
    'source': 'Custom Protocol Request',
    'description': '''This protocol is to normalize and pool all 5 tamGenetics plates.'''
}

def run(protocol):

    [pipette_type_s20,
     pipette_mount_s20,
     tip_type_s20,
     tip_reuse_s20,
     pipette_type_m20,
     pipette_mount_m20,
     tip_type_m20,
     tip_reuse_m20,
     transfer_csv] = get_values(  # noqa: F821
        "pipette_type_s20",
        "pipette_mount_s20",
        "tip_type_s20",
        "tip_reuse_s20",
        "pipette_type_m20",
        "pipette_mount_m20",
        "tip_type_m20",
        "tip_reuse_m20",
        "transfer_csv")

    # strip headers
    transfer_info = [[val.strip().lower() for val in line.split(',')]
                     for line in transfer_csv.splitlines()
                     if line.split(',')[0].strip()][1:]
    
    # load labware
    magdeck = protocol.load_module('magnetic module gen2', 1)
    pcr2Plate = magdeck.load_labware("nest_96_wellplate_100ul_pcr_full_skirt", label = 'pcr2Plate')
    normPlates = [protocol.load_labware("nest_96_wellplate_100ul_pcr_full_skirt", slot)
                  for slot in ['4', '7', '2', '5', '8']]
    poolPlate = protocol.load_labware("nest_96_wellplate_100ul_pcr_full_skirt", '3')

    for line in transfer_info:
        s_lw, s_slot, d_lw, d_slot = line[2:4] + line[5:7]
        for slot, lw in zip([s_slot, d_slot], [s_lw, d_lw]):
            if not int(slot) in protocol.loaded_labwares:
                protocol.load_labware(lw.lower(), slot)

    # load tipracks
    tipracks_s20 = [protocol.load_labware(tip_type_s20, slot)
            for slot in ['9']]
    tipracks_m20 = [protocol.load_labware(tip_type_m20, slot)
            for slot in ['10', '11']]

    # load pipettes
    s20 = protocol.load_instrument(pipette_type_s20, pipette_mount_s20, tip_racks=tipracks_s20)
    m20 = protocol.load_instrument(pipette_type_m20, pipette_mount_m20, tip_racks=tipracks_m20)
            
    tip_count_s20 = 0
    tip_max_s20 = len(tipracks_s20*96)

    tip_count_m20 = 0
    tip_max_m20 = len(tipracks_m20*96)

    def pick_up_s20():
        nonlocal tip_count_s20
        if tip_count_s20 == tip_max_s20:
            protocol.pause('Please refill 20 ul tipracks for m20 before resuming.')
            s20.reset_tipracks()
            tip_count_s20 = 0
        s20.pick_up_tip()
        tip_count_s20 += 1

    def pick_up_m20():
        nonlocal tip_count_m20
        if tip_count_m20 == tip_max_m20:
            protocol.pause('Please refill 20 ul tipracks for m20 before resuming.')
            m20.reset_tipracks()
            tip_count_m20 = 0
        m20.pick_up_tip()
        tip_count_m20 += 8

    def parse_well(well):
        letter = well[0]
        number = well[1:]
        return letter.upper() + str(int(number))

    if tip_reuse_m20 == 'never':
        pick_up_m20()

    # STEP 1: water transfer
    if tip_reuse_s20 == 'always':
        pick_up_s20()
    
    for line in transfer_info:
        if line[0].startswith('set1'):
            _, _, _, s_slot, s_well, _, d_slot, d_well, vol = line[:9]
            source = protocol.loaded_labwares[
                int(s_slot)].wells_by_name()[parse_well(s_well)].bottom(3)
            dest = protocol.loaded_labwares[
                int(d_slot)].wells_by_name()[parse_well(d_well)].bottom(1)
            if float(vol) < 5:
                s20.flow_rate.aspirate = 1
                s20.flow_rate.dispense = 1
            else:
                s20.flow_rate.aspirate = 7.6
                s20.flow_rate.dispense = 7.6
            s20.transfer(float(vol),
                        source,
                        dest,
                        touch_tip = True,
                        new_tip = 'never')
    if tip_reuse_s20 == 'always':
        s20.drop_tip()

    # PAUSE 1: Place plate 1 on magblock
    protocol.pause("PAUSE 1: Place plate 1 on magblock & resume run.")

    # STEP 2: sample transfer plate 1
    magdeck.engage()
    for line in transfer_info:
        if line[0].startswith('set2'):
            _, _, _, s_slot, s_well, _, d_slot, d_well, vol = line[:9]
            pcr2Plate1 = protocol.loaded_labwares[
                int(s_slot)].wells_by_name()[parse_well(s_well)].bottom(1)
            normPlate = protocol.loaded_labwares[
                int(d_slot)].wells_by_name()[parse_well(d_well)]
            if tip_reuse_m20 == 'always':
                pick_up_m20()
            m20.flow_rate.aspirate = 2
            m20.flow_rate.dispense = 2
            m20.transfer(float(vol),
                        pcr2Plate1,
                        normPlate,
                        new_tip = 'never')
            m20.flow_rate.aspirate = 7.6
            m20.flow_rate.dispense = 7.6
            m20.transfer(5,
                        normPlate,
                        poolPlate.columns()[0],
                        mix_before = (10, 4),
                        new_tip = 'never')
            if tip_reuse_m20 == 'always':
                m20.drop_tip()
    if m20.hw_pipette['has_tip']:
        m20.drop_tip()

    # PAUSE 2: Switch to plate 2
    protocol.pause("PAUSE 2: Switch to plate 2 & resume run.")

    # SET 3: sample transfer plate 2
    for line in transfer_info:
        if line[0].startswith('set3'):
            _, _, _, s_slot, s_well, _, d_slot, d_well, vol = line[:9]
            pcr2Plate2 = protocol.loaded_labwares[
                int(s_slot)].wells_by_name()[parse_well(s_well)].bottom(1)
            normPlate = protocol.loaded_labwares[
                int(d_slot)].wells_by_name()[parse_well(d_well)]
            if tip_reuse_m20 == 'always':
                pick_up_m20()
            m20.flow_rate.aspirate = 2
            m20.flow_rate.dispense = 2
            m20.transfer(float(vol),
                        pcr2Plate2,
                        normPlate,
                        new_tip = 'never')
            m20.flow_rate.aspirate = 7.6
            m20.flow_rate.dispense = 7.6
            m20.transfer(5,
                        normPlate,
                        poolPlate.columns()[1],
                        mix_before = (10, 4),
                        new_tip = 'never')
            if tip_reuse_m20 == 'always':
                m20.drop_tip()
    if m20.hw_pipette['has_tip']:
        m20.drop_tip()

    # PAUSE 3: Switch to plate 3
    protocol.pause("PAUSE 3: Switch to plate 3, REMOVE TIPS F6 & B12, & resume run.")

    # SET 4: sample transfer plate 3
    for line in transfer_info:
        if line[0].startswith('set4'):
            _, _, _, s_slot, s_well, _, d_slot, d_well, vol = line[:9]
            pcr2Plate3 = protocol.loaded_labwares[
                int(s_slot)].wells_by_name()[parse_well(s_well)].bottom(1)
            normPlate = protocol.loaded_labwares[
                int(d_slot)].wells_by_name()[parse_well(d_well)]
            if tip_reuse_m20 == 'always':
                pick_up_m20()
            m20.flow_rate.aspirate = 2
            m20.flow_rate.dispense = 2
            m20.transfer(float(vol),
                        pcr2Plate3,
                        normPlate,
                        new_tip = 'never')
            m20.flow_rate.aspirate = 7.6
            m20.flow_rate.dispense = 7.6
            m20.transfer(5,
                        normPlate,
                        poolPlate.columns()[2],
                        mix_before = (10, 4),
                        new_tip = 'never')
            if tip_reuse_m20 == 'always':
                m20.drop_tip()
    if m20.hw_pipette['has_tip']:
        m20.drop_tip()

    # PAUSE 4: Switch to plate 4
    protocol.pause("PAUSE 4: Switch to plate 4 & resume run.")

    # SET 5: sample transfer plate 4
    for line in transfer_info:
        if line[0].startswith('set5'):
            _, _, _, s_slot, s_well, _, d_slot, d_well, vol = line[:9]
            pcr2Plate4 = protocol.loaded_labwares[
                int(s_slot)].wells_by_name()[parse_well(s_well)].bottom(1)
            normPlate = protocol.loaded_labwares[
                int(d_slot)].wells_by_name()[parse_well(d_well)]
            if tip_reuse_m20 == 'always':
                pick_up_m20()
            m20.flow_rate.aspirate = 2
            m20.flow_rate.dispense = 2
            m20.transfer(float(vol),
                        pcr2Plate4,
                        normPlate,
                        new_tip = 'never')
            m20.flow_rate.aspirate = 7.6
            m20.flow_rate.dispense = 7.6
            m20.transfer(5,
                        normPlate,
                        poolPlate.columns()[3],
                        mix_before = (10, 4),
                        new_tip = 'never')
            if tip_reuse_m20 == 'always':
                m20.drop_tip()
    if m20.hw_pipette['has_tip']:
        m20.drop_tip()

    # PAUSE 5: Switch to plate 5
    protocol.pause("PAUSE 5: Switch to plate 5, REMOVE TIP C1 & resume run.")

    # SET 6: sample transfer plate 5
    for line in transfer_info:
        if line[0].startswith('set6'):
            _, _, _, s_slot, s_well, _, d_slot, d_well, vol = line[:9]
            pcr2Plate5 = protocol.loaded_labwares[
                int(s_slot)].wells_by_name()[parse_well(s_well)].bottom(1)
            normPlate = protocol.loaded_labwares[
                int(d_slot)].wells_by_name()[parse_well(d_well)]
            if tip_reuse_m20 == 'always':
                pick_up_m20()
            m20.flow_rate.aspirate = 2
            m20.flow_rate.dispense = 2
            m20.transfer(float(vol),
                        pcr2Plate5,
                        normPlate,
                        new_tip = 'never')
            m20.flow_rate.aspirate = 7.6
            m20.flow_rate.dispense = 7.6
            m20.transfer(5,
                        normPlate,
                        poolPlate.columns()[4],
                        mix_before = (10, 4),
                        new_tip = 'never')
            if tip_reuse_m20 == 'always':
                m20.drop_tip()
    if m20.hw_pipette['has_tip']:
        m20.drop_tip()
    magdeck.disengage()